async function run\(\) {
  const res = await fetch\(PLACES_API, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Goog-Api-Key': 'AIzaSyDO8rs_UsSLOTctSw9X_8Z5nuVwujkZmK4',
      'X-Goog-FieldMask': PLACES_FIELDS,
